const authData = $('Auth Gate').first().json;
const message = authData.message || $('Webhook').first().json.body.message;
const spreadsheetId = authData.spreadsheetId || '';

// Store spreadsheetId in execution custom data so toolWorkflow sub-nodes can access it
$execution.customData.set('spreadsheetId', spreadsheetId);

const learnings = $input.all() || [];
const projectName = 'cosmetic-formulator';

const relevantLearnings = learnings.filter(l => {
  const proj = (l.json.ProjectName || '').toLowerCase();
  const active = String(l.json.Active || '').toUpperCase();
  return active === 'TRUE' && (proj === projectName || proj === 'global');
});

let learningsSection = '';
if (relevantLearnings.length > 0) {
  learningsSection = 'LEARNED BEHAVIORS (from user feedback — always follow these):\n';
  for (const l of relevantLearnings) {
    learningsSection += '- ' + l.json.Learning + '\n';
  }
}

return [{ json: { message, learningsSection, spreadsheetId } }];

const output = $json.output || '';
const steps = $json.intermediateSteps || [];

let toolsUsed = [];
let traceLines = [];

for (let i = 0; i < steps.length; i++) {
  const step = steps[i];
  const action = step.action || {};
  const toolName = action.tool || 'unknown';
  const toolInput = action.toolInput || {};
  const observation = (step.observation || '').substring(0, 500);
  const reasoning = (action.log || '').trim();

  toolsUsed.push(toolName);
  traceLines.push('Step ' + (i + 1) + ': Called ' + toolName);
  if (reasoning) traceLines.push('  Reasoning: ' + reasoning.substring(0, 200));
  const inputStr = typeof toolInput === 'string'
    ? toolInput
    : Object.entries(toolInput).map(([k,v]) => k + '=' + v).join(', ');
  if (inputStr) traceLines.push('  Input: ' + inputStr);
  traceLines.push('  Result: ' + observation);
  traceLines.push('');
}

const decisionTrace = traceLines.length > 0
  ? traceLines.join('\n')
  : 'No tools were called for this response.';
const toolsList = [...new Set(toolsUsed)].join(', ');

const responseBody = JSON.stringify({ output, decisionTrace, toolsUsed: toolsList });

return [{ json: { output, decisionTrace, toolsUsed: toolsList, responseBody } }];

const webhookData = $('Webhook').first().json;
const token = (webhookData.headers || {})['x-auth-token'] || '';

// Reject missing or empty token immediately
if (!token) {
  return [{ json: { authorized: false, error: 'Unauthorized' } }];
}

const users = $input.all();

// No matching user found
if (!users || users.length === 0 || !users[0].json.AuthToken) {
  return [{ json: { authorized: false, error: 'Unauthorized' } }];
}

// Verify token actually matches (filter may return all rows on empty lookup)
const userIdx = users.findIndex(u => u.json.AuthToken === token);
if (userIdx === -1) {
  return [{ json: { authorized: false, error: 'Unauthorized' } }];
}

const u = users[userIdx].json;
const userRowNumber = userIdx + 2;

// Check if user is active
if (String(u.Active || '').toUpperCase() !== 'TRUE') {
  return [{ json: { authorized: false, error: 'Account inactive' } }];
}

// Check usage limit
const used = parseInt(u.ConversationsThisMonth || '0', 10);
const limit = parseInt(u.ConversationsLimit || '100', 10);
if (used >= limit) {
  return [{ json: { authorized: false, error: 'Monthly conversation limit reached (' + limit + '). Resets next month.' } }];
}

// User is authorized — pass through their config
return [{ json: {
  authorized: true,
  spreadsheetId: u.SpreadsheetId || '1cLv6rS_YjlTGVGrrpWFt7TMz4el1SOsYwlDmzwOwKXI',
  email: u.Email || '',
  plan: u.Plan || 'basic',
  conversationsUsed: used,
  conversationsLimit: limit,
  userRowNumber: userRowNumber,
  message: webhookData.body.message,
  sessionId: webhookData.body.sessionId || ''
}}];

// Increment usage counter for the authenticated user
const authData = $('Auth Gate').first().json;
const rowNum = authData.userRowNumber || 0;
const newCount = (authData.conversationsUsed || 0) + 1;

if (!rowNum) {
  return [{ json: { incremented: false } }];
}

return [{ json: {
  incremented: true,
  rowNumber: rowNum,
  newCount: newCount
}}];
